-- 更新settings
UPDATE `custom_settings` SET  `value` = '{\r\n  \"enable_weekly_plan\": true,\r\n  \"enable_differential_display\": true,\r\n  \"call_state_to_be_compared\": [],\r\n  \"tot_state_to_be_compared\": [],\r\n  \"tot_type_mapping\": {\r\n    \"tot_type_id\": \"weekly_plan__tot_id\"\r\n  },\r\n  \"enable_call_finish_action\": true,\r\n  \"enable_coaching_finish_action\": true,\r\n  \"calendar_timeline\": {\r\n    \"every_day_range_time\": {\r\n      \"am\": [\r\n        \"08:00:00\",\r\n        \"12:00:00\"\r\n      ],\r\n      \"pm\": [\r\n        \"12:00:00\",\r\n        \"18:00:00\"\r\n      ]\r\n    },\r\n    \"unknown_max_minutes\": 30,\r\n    \"objects\": {\r\n      \"time_off_territory\": {\r\n        \"__default__\": {\r\n          \"values\": {\r\n            \"am\": [\r\n              \"forenoon\"\r\n            ],\r\n            \"pm\": [\r\n              \"afternoon\"\r\n            ]\r\n          },\r\n          \"column_names\": [\r\n            \"date\",\r\n            \"ampm\"\r\n          ],\r\n          \"type\": \"ampm\"\r\n        }\r\n      },\r\n      \"coaching\": {\r\n        \"__default__\": {\r\n          \"column_names\": [\r\n            \"coaching_date\"\r\n          ],\r\n          \"type\": \"date\"\r\n        }\r\n      },\r\n      \"call\": {\r\n        \"__default__\": {\r\n          \"column_names\": [\r\n            \"call_date\"\r\n          ],\r\n          \"type\": \"date\"\r\n        }\r\n      },\r\n      \"event\": {\r\n        \"__default__\": {\r\n          \"column_names\": [\r\n            \"event_start_time\",\r\n            \"event_end_time\"\r\n          ],\r\n          \"type\": \"range\"\r\n        }\r\n      },\r\n      \"weekly_plan\": {\r\n        \"__default__\": {\r\n          \"values\": {\r\n            \"am\": [\r\n              \"am\"\r\n            ],\r\n            \"pm\": [\r\n              \"pm\"\r\n            ]\r\n          },\r\n          \"column_names\": [\r\n            \"date\",\r\n            \"ampm\"\r\n          ],\r\n          \"type\": \"ampm\"\r\n        },\r\n        \"weekly_plan_coaching_plans\": {\r\n          \"column_names\": [\r\n            \"start_time\",\r\n            \"end_time\"\r\n          ],\r\n          \"type\": \"range\"\r\n        },\r\n        \"weekly_plan_call_plans\": {\r\n          \"column_names\": [\r\n            \"start_time\",\r\n            \"end_time\"\r\n          ],\r\n          \"type\": \"range\"\r\n        }\r\n      }\r\n    }\r\n  }\r\n}' WHERE `key` = 'calendar_display_mode_setting';


-- assign 代表和主管


UPDATE custom_settings SET value='[{"fields": [{"type": "date", "name": "call_date"}], "object_name": "call"}, {"fields": [{"type": "date", "name": "coaching_date"}], "object_name": "coaching"}, {"fields": [{"type": "datetime", "name": "event_start_time","time_tag":"start"}, {"type": "datetime", "name": "event_end_time","time_tag":"end"}], "object_name": "event"},{"fields": [{"type": "datetime", "name": "start_time","time_tag":"start"},{"type": "datetime", "name": "end_time","time_tag":"end"}], "object_name": "weekly_plan"},{"fields": [{"type": "date", "name": "date"}], "object_name": "time_off_territory"}]'
WHERE `key`='calendar_create_data_config';


